local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxEquipCtrl:LxBaseCtrl
local LxEquipCtrl = classX("LxEquipCtrl", LxBaseCtrl)

function LxEquipCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
    self:InitEquipLvRef()
end

function LxEquipCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end
--- 把强化表 拆分成 品级跟等级作为索引
function LxEquipCtrl:InitEquipLvRef()
    self._FilterLvRef = {}
    local eqStRefList = GameTable.EquipLvRef
    for i, v in ipairs(eqStRefList) do
        if not self._FilterLvRef[v.quality] then
            self._FilterLvRef[v.quality] = {}
        end
        self._FilterLvRef[v.quality][v.level] = v
    end
end
--- 根据品质 跟等级 获取对应配置
function LxEquipCtrl:GetFilterLvRef(quality, lv)
    if table.isempty(self._FilterLvRef) then
        self:InitEquipLvRef()
    end
    quality = quality or 1
    if not lv then
        return self._FilterLvRef[quality]
    end
    return self._FilterLvRef[quality][lv]
end
