--- 获取装备堆叠的展示列表 堆叠规则 一样的部位 一样的装备refId 一样的强化等级 一样的星级 ，已穿戴的 不用堆叠
--- @param isWear boolean 是否筛选已穿戴的
--- @param upShow boolean 是否只显示可强化的
function LxEquipCtrl:GetEquipPileUpList(isWear, upShow)
    local eqModule = ModuleCenter.Equip
    local eqMap = eqModule:GetEquipBagMap()
    local eqRefList = GameTable.RoleEquipRef
    local lvUpShow = GameTable.RoleEquipConfigRef.lvUpShow
    local pileUpList = {}
    local showList = {}
    for i, v in pairs(eqMap) do
        if not isWear or v.heroId == "0" then
            local ref = eqRefList[v.refId]
            if not upShow or (upShow and ref.quality < lvUpShow) then
                local _key = ""
                if v.heroId ~= "0" then
                    _key = v.heroId .."_" .. v.refId
                else
                    _key = _key .. v.refId .. v.level .. v.star
                end
                if not pileUpList[_key] then
                    pileUpList[_key] = {}
                    pileUpList[_key].power = v.power
                    pileUpList[_key].refId = v.refId
                    pileUpList[_key].heroId = v.heroId
                    pileUpList[_key].sort = eqRefList[v.refId].type
                    pileUpList[_key].ids = {}
                end
                table.insert(pileUpList[_key].ids, v.id)
            end
        end
    end
    for i, v in pairs(pileUpList) do
        table.insert(showList, v)
    end
    table.sort(showList, function(a, b)
        if a.power ~= b.power then
            return a.power < b.power
        else
            return a.sort < b.sort
        end
    end)
    return showList
end
--- 检查这个英雄是否存在更好的装备
--- @param heroObj LxHeroObj
function LxEquipCtrl:CheckBetterEquipByHeroObj(heroObj)
    local equips = heroObj.equips
    for i, v in ipairs(equips) do
        local isBetter, _ = self:CheckBetterEquip(heroObj.heroRef.careerType, i, v)
        if isBetter then
            return true
        end
    end
    return false
end


--- 检查是否存在更好的装备
--- @param career number 职业
--- @param part number 部位
--- @param curEquipId string 当前的装备id
--- @return boolean 是否存在更好的装备
function LxEquipCtrl:CheckBetterEquip(career, part, curEquipId)
    local eqModule = ModuleCenter.Equip
    local eqMap = eqModule:GetEquipBagMap()
    local eqRefList = GameTable.RoleEquipRef
    local curEquipInfo
    local curPower = 0
    local betterId = ""
    if not string.isempty(curEquipId) and curEquipId ~= "0" then
        curEquipInfo = eqMap[curEquipId]
        curPower = curEquipInfo.power
    end
    for _, v in pairs(eqMap) do
        local ref = eqRefList[v.refId]
        if v.heroId == "0" then
            if career == ref.career and part == ref.type and v.power > curPower then
                betterId = v.id
                curPower = v.power
            end
        end
    end
    return not string.isempty(betterId), betterId
end
--- 根据部位获取装备列表
--- @param career number 职业
--- @param part number 部位
--- @param isHide boolean 是否隐藏已穿戴的装备
function LxEquipCtrl:GetEquipListByPart(career, part, isHide, heroId)
    local eqModule = ModuleCenter.Equip
    local eqMap = eqModule:GetEquipBagMap()
    local eqRefList = GameTable.RoleEquipRef
    local showList = {}
    for _, v in pairs(eqMap) do
        local ref = eqRefList[v.refId]
        if career == ref.career and part == ref.type and heroId ~= v.heroId then
            if isHide then
                if v.heroId == "0" then
                    table.insert(showList, v)
                end
            else
                table.insert(showList, v)
            end
        end
    end
    table.sort(showList, function(a, b) return a.power > b.power end)
    return showList
end
--- 获取当前装备的强化属性
function LxEquipCtrl:GetStrengthAttr(refId, level)
    local eqRef = GameTable.RoleEquipRef[refId]
    local eqStRef = self:GetFilterLvRef(eqRef.quality, level)
    local lvRatio = eqStRef.attr
    -- 基础属性
    local attrList = LxDataHelper.ParseAttrStr(eqRef.attr)
    for i, v in ipairs(attrList) do
        local value = attrList[i].value
        attrList[i].value = value * lvRatio
    end
    return attrList
end
--- 获取星级属性 升星属性=（初始属性*强化系数）*升星系数
function LxEquipCtrl:GetStarAttr(refId, level, star)
    local lvAttrList = self:GetStrengthAttr(refId, level)
    local eqStarRef = GameTable.EquipStarRef[star]
    local lvRatio = eqStarRef.attrAdd
    for i, v in ipairs(lvAttrList) do
        local value = lvAttrList[i].value
        lvAttrList[i].value = value * lvRatio
    end
    return lvAttrList
end
--- 装备战力
function LxEquipCtrl:GetEquipPower(refId, level, star)
    local eqRef = GameTable.RoleEquipRef[refId]
    local eqStRef = self:GetFilterLvRef(eqRef.quality, level)
    local eqStarRef = GameTable.EquipStarRef[star]
    local power = eqRef.power * eqStRef.power * eqStarRef.power
    return power
end
--- 获取本体装备
--- @param isWear boolean true 已被穿戴的装备也筛选进去 false 忽略已被穿戴的装备
function LxEquipCtrl:GetEquipListByRefId(refId, isWear)
    local eqModule = ModuleCenter.Equip
    local eqMap = eqModule:GetEquipBagMap()
    local showList = {}
    for i, v in pairs(eqMap) do
        if v.refId == refId and (v.heroId == "0" or isWear) then
            table.insert(showList, v)
        end
    end
    table.sort(showList, function(a, b)
        return a.power < b.power
    end)
    return showList
end
--- 获取所有装备
--- @param isWear boolean 是否筛选已穿戴的
function LxEquipCtrl:GetEquipList(isWear)
    local list = {}
    local equipList = ModuleCenter.Equip:GetEquipBagMap()
    for i, v in pairs(equipList) do
        if v.heroId == "0" or isWear then
            table.insert(list, v)
        end
    end
    return list
end
--出战（主线冒险）的英雄，有可强化的装备，主界面英雄图标->英雄列表界面半身像图标->英雄装备界面分页->英雄装备图标->装备tips【养成】按钮->强化分页，显示红点
--出战（主线冒险）的英雄，有可升星的装备主界面英雄图标->英雄列表界面半身像图标->英雄装备界面分页->英雄装备图标->装备tips【养成】按钮->升星分页，显示红点
--出战（主线冒险）的英雄，有可穿戴/替换的装备时，主界面英雄图标->英雄列表界面半身像图标->英雄装备界面分页，显示红点
--- @param heroObj LxHeroObj 检查该英雄是否存在装备红点
function LxEquipCtrl:CheckEquipRedByHeroObj(heroObj)
    local isOpen = CtrlCenter.FuncOpen:IsFuncOpen(FuncIds.Equip)
    if not isOpen then
        return false
    end
    if CtrlCenter.Formation:CheckHeroIsInnerIns(heroObj) then
        -- 当前英雄的强化红点
        if self:CheckStrengthRedByHeroObj(heroObj) then
            return true
        end
        -- 当前英雄的升星红点
        if self:CheckUpStarRed(heroObj) then
            return true
        end
        -- 装备穿戴红点
        if self:CheckWearRed(heroObj) then
            return true
        end
    end
    return false
end

--- @param heroObj LxHeroObj 检查该英雄是否存在可升级红点
function LxEquipCtrl:CheckStrengthRedByHeroObj(heroObj)
    local equips = heroObj.equips
    local eqModule = ModuleCenter.Equip
    --- 从最小等级开始排序的装备
    local sortEquips = {}
    for i, v in ipairs(equips) do
        if v ~= "0" then
            local equipObj = eqModule:GetEquipInfo(v)
            table.insert(sortEquips, equipObj)
        end
    end
    table.sort(sortEquips, function(a, b)
        return a.level < b.level
    end)
    for _, v in ipairs(sortEquips) do
        if self:CheckEquipStrengthRed(v) then
            return true
        end
    end

    return false
end
--- @param equipObj LxEquipObj 检查该装备是否可强化
function LxEquipCtrl:CheckEquipStrengthRed(equipObj)
    if table.isempty(equipObj) then
        return false
    end
    local equipRefList = GameTable.RoleEquipRef
    local itemRefList = GameTable.PlayerItemRef
    local lvShow = GameTable.RoleEquipConfigRef.lvUpShow
    local ref = equipRefList[equipObj.refId]
    local curLevel = equipObj.level
    local curExp = equipObj.exp
    if curLevel >= ref.maxLv then
        return false
    end

    local lvRef = self:GetFilterLvRef(ref.quality, curLevel)
    local needExp = lvRef.needExp - curExp   -- 升级需要的经验
    local totalExp = 0
    local itemList = CtrlCenter.Item:GetItemListByType(Item_Types.T_EquipItem)
    local equipList = self:GetEquipList()
    --- 强化道具
    for _, v in ipairs(itemList) do
        local itemRef = itemRefList[v.refId]
        totalExp = totalExp + v.num * itemRef.typeDate
        if totalExp >= needExp then
            return true
        end
    end
    --- 装备
    for _, v in ipairs(equipList) do
        local eqRef = equipRefList[v.refId]
        if eqRef.quality < lvShow then
            totalExp = totalExp + v.exp + eqRef.resolve
            if totalExp >= needExp then
                return true
            end
            if v.level > 0 then
                for n = 0, v.level - 1 do
                    local _lvRef = self:GetFilterLvRef(ref.quality, n)
                    totalExp = totalExp + _lvRef.needExp + v.exp
                    if totalExp >= needExp then
                        return true
                    end
                end
            end
        end
    end
    return false
end

--- 获取装备强化道具
--- @return table<number, number> key 道具id
function LxEquipCtrl:GetEquipStrengthItem()
    if not self._strengthItem then
        self._strengthItem = {}
        local itemList = CtrlCenter.Item:GetItemListByType(Item_Types.T_EquipItem)
        for _, v in ipairs(itemList) do
            self._strengthItem[v.refId] = true
        end
    end
    return self._strengthItem
end
--- @param heroObj LxHeroObj 英雄的装备升星红点
function LxEquipCtrl:CheckUpStarRed(heroObj)
    local equips = heroObj.equips
    local eqModule = ModuleCenter.Equip
    for _, v in ipairs(equips) do
        if v ~= "0" then
            local equipObj = eqModule:GetEquipInfo(v)
            if self:CheckEquipUpStarRed(equipObj) then
                return true
            end
        end
    end
    return false
end
--- @param equipObj LxEquipObj 装备升星红点
function LxEquipCtrl:CheckEquipUpStarRed(equipObj)
    local eqRefList = GameTable.RoleEquipRef
    local itemModule = ModuleCenter.Item
    local eqRef = eqRefList[equipObj.refId]
    if eqRef.upStar == 0 then
        return false
    end
    local isMax = equipObj.star >= #GameTable.EquipStarRef
    if isMax then
        return false
    end
    local curStarRef = GameTable.EquipStarRef[equipObj.star]
    -- 所需要的道具
    local itemList = LxDataHelper.ParseItemStrList(curStarRef.upNeedItem)
    -- 本体
    local needNum = curStarRef.upNeedEquip
    for _, v in ipairs(itemList) do
        local hasNum = itemModule:GetItemCount(v.refId)
        if hasNum < v.num then
            return false
        end
    end
    if needNum > 0 then
        local list = self:GetEquipListByQuality(eqRef.quality)
        if #list < needNum then
            return false
        end
    end
    return true
end
--- @param heroObj LxHeroObj 英雄的装备穿戴/更好的装备红点
function LxEquipCtrl:CheckWearRed(heroObj)
    local equips = heroObj.equips
    local heroRef = heroObj.heroRef
    for i, v in ipairs(equips) do
        if self:CheckBetterEquip(heroRef.careerType, i, v) then
            return true
        end
    end
    return false
end

--- 根据品质获取未穿戴跟未升星的装备列表
function LxEquipCtrl:GetEquipListByQuality(quality)
    local eqModule = ModuleCenter.Equip
    local eqMap = eqModule:GetEquipBagMap()
    local equipRefList = GameTable.RoleEquipRef
    local showList = {}
    for _, v in pairs(eqMap) do
        local ref = equipRefList[v.refId]
        if ref.quality == quality and v.star == 0 and v.heroId == "0" then
            table.insert(showList, v)
        end
    end
    table.sort(showList, function(a, b)
        if a.power ~= b.power then
            return a.power < b.power
        end
        return a.refId < b.refId
    end)
    return showList
end
return LxEquipCtrl
